    pub fn parse_ledger_entry(&self, mut item: Value, optional_args: &[Value]) -> Value {
        let mut currency = get_arg(optional_args, 0, Value::Null);
        //
        // {
        //     "id": "6a6075bc-7183-5fd9-bc9d-894e238aa527",
        //     "sender": {
        //         "address": "dydx14zzueazeh0hj67cghhf9jypslcf9sh2n5k6art",
        //         "subaccountNumber": 0
        //     },
        //     "recipient": {
        //         "address": "dydx1slanxj8x9ntk9knwa6cvfv2tzlsq5gk3dshml0",
        //         "subaccountNumber": 1
        //     },
        //     "size": "0.000001",
        //     "createdAt": "2025-07-29T09:43:02.105Z",
        //     "createdAtHeight": "45116125",
        //     "symbol": "USDC",
        //     "type": "TRANSFER_OUT",
        //     "transactionHash": "92B4744BA1B783CF37C79A50BEBC47FFD59C8D5197D62A8485D3DCCE9AF220AF"
        // }
        //
        let mut currencyId: Value = self.safe_string_k(item.clone(), "symbol", &[]);
        let mut code: Value = self.safe_currency_code(currencyId.clone(), &[currency.clone()]);
        currency = self.safe_currency(currencyId.clone(), &[currency.clone()]);
        let mut type_var: Value = self.safe_string_upper(item.clone(), Value::Str("type".to_string()), &[]);
        let mut direction: Value = Value::Null;
        if !is_equal(&type_var, &Value::Null) {
            if is_equal(&type_var, &Value::Str("TRANSFER_IN".to_string())) || is_equal(&type_var, &Value::Str("DEPOSIT".to_string())) {
                direction = Value::Str("in".to_string());
            }  else if is_equal(&type_var, &Value::Str("TRANSFER_OUT".to_string())) || is_equal(&type_var, &Value::Str("WITHDRAWAL".to_string())) {
                direction = Value::Str("out".to_string());
            }
        }
        let mut amount: Value = self.safe_string_k(item.clone(), "size", &[]);
        let mut timestamp: Value = self.parse8601(self.safe_string_k(item.clone(), "createdAt", &[]));
        let mut sender: Value = self.safe_dict_k(item.clone(), "sender", &[]);
        let mut recipient: Value = self.safe_dict_k(item.clone(), "recipient", &[]);
        return self.safe_ledger_entry(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), item.clone());
        m.insert("id".to_string(), self.safe_string_k(item.clone(), "id", &[]));
        m.insert("direction".to_string(), direction.clone());
        m.insert("account".to_string(), self.safe_string_k(sender.clone(), "address", &[]));
        m.insert("referenceAccount".to_string(), self.safe_string_k(recipient.clone(), "address", &[]));
        m.insert("referenceId".to_string(), self.safe_string_k(item.clone(), "transactionHash", &[]));
        m.insert("type".to_string(), self.parse_ledger_entry_type(type_var.clone()));
        m.insert("currency".to_string(), code.clone());
        m.insert("amount".to_string(), self.parse_number(amount.clone(), &[]));
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("before".to_string(), Value::Null);
        m.insert("after".to_string(), Value::Null);
        m.insert("status".to_string(), Value::Null);
        m.insert("fee".to_string(), Value::Null);
    m
}), &[currency.clone()]);

    Value::Null
}

